queries.sparql:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:platformsID ?cg . ?child a :Platforms ; p:platformID ?cg . ?l p:gamesID ?pg . ?parent a :Games ; p:gameID ?pg . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Games } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE scope {
  distributive: { SELECT ?title ?name WHERE {
  ?games_platforms a :Games_Platforms .
  ?platforms a :Platforms .
  ?games_platforms p:hasPlatforms ?platforms .
  ?games a :Games .
  ?games_platforms p:hasGames ?games .
  ?games p:title ?title .
  ?platforms p:name ?name .
} }
  collective: { SELECT ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:platformsID ?cg . ?child a :Platforms ; p:platformID ?cg . ?l p:gamesID ?pg . ?parent a :Games ; p:gameID ?pg . } GROUP BY ?child }
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Games } }
  FILTER(?nf = ?total)
} }
}
